---------------------
---- LAYER RULES ----
---------------------

hl.layer_rule({ match = { namespace = "waybar" },                 blur = true,  ignore_alpha = 0.0 })
hl.layer_rule({ match = { namespace = "quickshell" },             blur = true,  ignore_alpha = 0.0 })

---------------------
---- WINDOW RULES ---
---------------------

-- Gaming — allow tearing
hl.window_rule({ match = { class = "steam_app_" },                  immediate = true })
hl.window_rule({ match = { class = "Minecraft" },                   immediate = true })
-- gaming-toggle.sh runs `gamescope -- steam -bigpicture`; the window class is
-- "gamescope", not "steam", so the Big Picture rule below never matches it.
-- Without fullscreen it stays a tiled window that Hyprland composites every
-- frame at vsync (major input lag). fullscreen + immediate lets Hyprland
-- direct-scanout the gamescope buffer straight to the display, near-native.
hl.window_rule({ match = { class = "gamescope" },                   fullscreen = true })
hl.window_rule({ match = { class = "gamescope" },                   immediate = true })

-- Launchers
-- Big Picture launched natively by gaming-toggle.sh: fullscreen + immediate so
-- Hyprland direct-scanouts it (no compositor vsync latency).
hl.window_rule({ match = { class = "steam",   title = "Steam Big Picture Mode" }, fullscreen = true })
hl.window_rule({ match = { class = "steam",   title = "Steam Big Picture Mode" }, immediate = true })
-- Steam dropdown menus are empty-title XWayland popups; without this they
-- steal focus and land on the wrong monitor.
hl.window_rule({ match = { class = "steam", title = "^$" }, no_focus = true })

-- Float
hl.window_rule({ match = { class = "pavucontrol" },        float = true })
hl.window_rule({ match = { class = "nm-connection-editor" }, float = true })
hl.window_rule({ match = { class = "blueman-manager" },    float = true })
hl.window_rule({ match = { title = "Picture-in-Picture" }, float = true })

-- Scratchpad — windows on a special workspace float centred with an orange
-- border so they read as scratchpad windows, not tiles. The static fields
-- (float/size/center) only apply to windows that open on the special; the
-- Super+Shift+S bind replicates them for windows moved there. Also used by
-- the per-app scratchpads defined with their binds below.
local function scratchpadRule(name)
    hl.window_rule({
        name  = "scratchpad-style-" .. name,
        -- The workspace matcher needs the "name:" prefix for named specials —
        -- a bare "special:X" parses as an id selector and matches nothing.
        match = { workspace = "name:special:" .. name },

        float        = true,
        size         = "65% 65%",
        center       = true,
        border_color = "rgba(@orange-hex@ee)",
    })
end
scratchpadRule("magic")

-- Opacity
hl.window_rule({ match = { class = "kitty" },        opacity = "0.90 override 0.90 override" })
hl.window_rule({ match = { class = "cava" },         opacity = "0.90 override 0.90 override" })
hl.window_rule({ match = { class = "firefox" },      opacity = "1.0 override 1.0 override" })
hl.window_rule({ match = { class = "chromium" },     opacity = "1.0 override 1.0 override" })
hl.window_rule({ match = { class = "google-chrome" },opacity = "1.0 override 1.0 override" })


--------------------
---- KEYBINDS ------
--------------------

local mainMod = "SUPER"

-- Apps
hl.bind(mainMod .. " + Return",     hl.dsp.exec_cmd(apps.terminal),                   { description = "Apps | Terminal" })
hl.bind(mainMod .. " + E",          hl.dsp.exec_cmd("thunar"),                        { description = "Apps | Files" })
