hl.bind(mainMod .. " + SHIFT + F", hl.dsp.window.fullscreen_state({ client = 0, internal = 3 }),      { description = "Window | Fullscreen (fake)" })
hl.bind(mainMod .. " + Space",     hl.dsp.window.float({ action = "toggle" }),                        { description = "Window | Toggle float" })
hl.bind(mainMod .. " + P",         hl.dsp.window.pseudo(),                                            { description = "Window | Pseudo tile" })
hl.bind(mainMod .. " + J",         hl.dsp.layout("togglesplit"),                                      { description = "Window | Toggle split" })

-- Focus
hl.bind(mainMod .. " + left",  hl.dsp.focus({ direction = "left" }),  { description = "Focus | Left" })
hl.bind(mainMod .. " + right", hl.dsp.focus({ direction = "right" }), { description = "Focus | Right" })
hl.bind(mainMod .. " + up",    hl.dsp.focus({ direction = "up" }),    { description = "Focus | Up" })
hl.bind(mainMod .. " + down",  hl.dsp.focus({ direction = "down" }),  { description = "Focus | Down" })

-- Move window
hl.bind(mainMod .. " + SHIFT + left",  hl.dsp.window.move({ direction = "left" }),  { description = "Move | Left" })
hl.bind(mainMod .. " + SHIFT + right", hl.dsp.window.move({ direction = "right" }), { description = "Move | Right" })
hl.bind(mainMod .. " + SHIFT + up",    hl.dsp.window.move({ direction = "up" }),    { description = "Move | Up" })
hl.bind(mainMod .. " + SHIFT + down",  hl.dsp.window.move({ direction = "down" }),  { description = "Move | Down" })

-- Resize window
hl.bind(mainMod .. " + CTRL + left",  hl.dsp.window.resize({ x = -50, y = 0 }),   { description = "Resize | Left" })
hl.bind(mainMod .. " + CTRL + right", hl.dsp.window.resize({ x = 50,  y = 0 }),   { description = "Resize | Right" })
hl.bind(mainMod .. " + CTRL + up",    hl.dsp.window.resize({ x = 0,   y = -50 }), { description = "Resize | Up" })
hl.bind(mainMod .. " + CTRL + down",  hl.dsp.window.resize({ x = 0,   y = 50 }),  { description = "Resize | Down" })

-- Workspaces 1–10
for i = 1, 10 do
    local key = tostring(i % 10)  -- 10 maps to "0"
    hl.bind(mainMod .. " + " .. key,         hl.dsp.focus({ workspace = i }),       { description = "Workspaces | Switch to " .. i })
    hl.bind(mainMod .. " + SHIFT + " .. key, hl.dsp.window.move({ workspace = i }), { description = "Workspaces | Move to " .. i })
end

-- Scroll through workspaces
hl.bind(mainMod .. " + mouse_down", hl.dsp.focus({ workspace = "e+1" }), { description = "Workspaces | Next" })
hl.bind(mainMod .. " + mouse_up",   hl.dsp.focus({ workspace = "e-1" }), { description = "Workspaces | Prev" })

-- Scratchpad
hl.bind(mainMod .. " + S",         hl.dsp.workspace.toggle_special("magic"),             { description = "Workspaces | Toggle scratchpad" })
-- Toggle-move: windows already in a scratchpad go back to the monitor's
-- workspace instead of piling up (the emptied special auto-closes — don't
-- toggle it here, that reopens it). Stashed windows are floated/sized by
-- hand: the scratchpad-style rule's static fields only apply to windows
-- that *open* on the special, not ones moved there. Windows the stash
-- floated are remembered and re-tiled on return; windows that were already
-- floating keep floating.
local scratchpadFloated = {}
hl.bind(mainMod .. " + SHIFT + S", function()
    local win = hl.get_active_window()
    if not win or not win.workspace then return end
    if win.workspace.special then
        local mon = hl.get_active_monitor()
        local target = mon and mon.active_workspace
        if not target then return end
        hl.dispatch(hl.dsp.window.move({ workspace = target.id }))
        if scratchpadFloated[win.address] then
            scratchpadFloated[win.address] = nil
            hl.dispatch(hl.dsp.window.float({ action = "disable" }))
        end
    else
        hl.dispatch(hl.dsp.window.move({ workspace = "special:magic" }))
        local mon = hl.get_active_monitor()
        if mon then
            if not win.floating then scratchpadFloated[win.address] = true end
            -- Monitor width/height are pre-transform; swap for portrait.
            local w, h = mon.width / mon.scale, mon.height / mon.scale
            if mon.transform % 2 == 1 then w, h = h, w end
            hl.dispatch(hl.dsp.window.float({ action = "enable" }))
            hl.dispatch(hl.dsp.window.resize({ x = math.floor(w * 0.65), y = math.floor(h * 0.65), exact = true }))
            hl.dispatch(hl.dsp.window.center())
        end
    end
end, { description = "Workspaces | Move to/from scratchpad" })

-- Waybar's scratchpad badge is signal-driven (interval "once" + RTMIN+9 in
-- modules/home/wm/waybar.nix) — poke it on the events that can change the
-- special-workspace window count. Toggling a special's visibility doesn't
-- change the count, so it needs no poke.
local function pokeScratchpadBadge()
    hl.exec_cmd("pkill -RTMIN+9 waybar")
end
for _, ev in ipairs({ "window.open", "window.close", "window.move_to_workspace" }) do
    hl.on(ev, pokeScratchpadBadge)
end

-- Recording indicator (RTMIN+10): screenshare.state fires on both edges of
-- any compositor-visible capture (wlr-screencopy, portal shares — verified
-- with grim). KMS-mode gpu-screen-recorder grabs DRM planes behind the
-- compositor and fires nothing; the module keeps a slow fallback poll whose
-- pgrep branch catches that case.
hl.on("screenshare.state", function()
    hl.exec_cmd("pkill -RTMIN+10 waybar")
end)

-- Per-app scratchpads — run-or-raise: first press spawns the app into its
-- own special workspace (so the scratchpad-style rule applies at open);
-- afterwards the same key just toggles that special. The query is scoped to
-- the special so a window dragged out to a normal workspace is left alone
-- and a fresh instance spawns.
local scratchpads = {
    { key = "grave",         name = "term", class = "dropterm",  cmd = "kitty --class dropterm",          label = "Terminal" },
    { key = "SHIFT + grave", name = "btop", class = "btop-drop", cmd = "kitty --class btop-drop -e btop", label = "btop" },
}
for _, pad in ipairs(scratchpads) do
    scratchpadRule(pad.name)
    hl.bind(mainMod .. " + " .. pad.key, function()
        if #hl.get_windows({ class = pad.class, workspace = "special:" .. pad.name }) == 0 then
            hl.dispatch(hl.dsp.exec_cmd("[workspace special:" .. pad.name .. "] " .. pad.cmd))
        else
            hl.dispatch(hl.dsp.workspace.toggle_special(pad.name))
        end
    end, { description = "Workspaces | Scratchpad: " .. pad.label })
end

